import{_ as o,o as t,c as i,ag as r}from"./chunks/framework.R9ZDD-VK.js";const c=JSON.parse('{"title":"Overview","description":"","frontmatter":{"title":"Overview","order":0},"headers":[],"relativePath":"guide/overview.md","filePath":"guide/overview.md"}'),n={name:"guide/overview.md"};function a(l,e,s,g,u,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p><strong>vue3-google-login</strong> is a lightweight, production-ready Vue 3 plugin for implementing Google Sign In, Google authentication, and OAuth2 login flows in your Vue 3 applications. This package provides seamless integration with <a href="https://developers.google.com/identity" target="_blank" rel="noreferrer">Google Identity Services</a> and the <a href="https://developers.google.com/identity/oauth2/web/guides/load-3p-authorization-library" target="_blank" rel="noreferrer">Google 3P Authorization JavaScript Library</a>, making it easy to add Google login functionality to your Vue 3 projects.</p><blockquote><p><strong>Using Nuxt?</strong> The recommended way to integrate this plugin in a Nuxt app is via the dedicated wrapper module → <a href="https://www.npmjs.com/package/nuxt-vue3-google-login" target="_blank" rel="noreferrer">nuxt-vue3-google-login</a></p></blockquote><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Login with Google button</strong> - Pre-styled Google sign-in button component</li><li><strong>One Tap prompt</strong> - Quick Google account selection for faster login experience</li><li><strong>Automatic Login</strong> - Seamless authentication without any user interaction</li><li><strong>Custom Login Button</strong> - Use your own button design with Google OAuth2 authentication</li><li><strong>TypeScript Support</strong> - Complete TypeScript definitions and type safety</li><li><strong>Lightweight &amp; Fast</strong> - Minimal bundle size, optimized performance</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before using vue3-google-login in your Vue 3 project, ensure you have:</p><ul><li><strong>Vue 3.0.3 or above</strong> - This plugin requires Vue 3.0.3 or higher</li><li><strong>Google API Client ID</strong> - To enable Google Sign In on your website, you need to set up your Google API client ID. <a href="https://developers.google.com/identity/gsi/web/guides/get-google-api-clientid" target="_blank" rel="noreferrer">Follow these steps</a> to get your client ID</li><li><strong>Local Development Setup</strong> - For testing in your local environment, add <code>http://localhost</code> and <code>http://localhost:&lt;port_number&gt;</code> to the Authorized JavaScript origins in your Google Cloud Console</li></ul>',8)])])}const h=o(n,[["render",a]]);export{c as __pageData,h as default};
